class Solution:
    def minStable(self, nums: List[int], maxC: int) -> int:
        def check(stability_factor):
            modifications = 0
            i = 0
            for j in range(len(nums)):
                if nums[j] % 2 == 1:
                    modifications += 1
                if j - i + 1 > stability_factor:
                    if nums[i] % 2 == 1:
                        modifications -= 1
                    i += 1
                if modifications > maxC:
                    return False
            return True

        even_count = sum(1 for num in nums if num % 2 == 0)
        if even_count == 0:
            return 0 if maxC == 0 else 1

        left, right = 1, len(nums)
        while left <= right:
            mid = (left + right) // 2
            if check(mid):
                left = mid + 1
            else:
                right = mid - 1
        return right if right > 0 else 0

